function calculateReputationalRisk(inputs) {
  const { 
    socialMediaSentimentScore, 
    negativeMediaMentionsLastQuarter, 
    ethicalPolicyAdherenceScore, 
    pastControversySeverityIndex, 
    publicTransparencyPerception, 
    crisisCommunicationPreparedness, 
    stakeholderTrustIndex, 
    regulatoryComplianceHistory 
  } = inputs;

  // Input validation and clamping
  const clamp = (val, min, max) => Math.min(Math.max(val, min), max);

  const sMSS = clamp(socialMediaSentimentScore, 0, 100);
  const nMMM = Math.max(0, negativeMediaMentionsLastQuarter); // Cannot be negative
  const ePAS = clamp(ethicalPolicyAdherenceScore, 0, 100);
  const pCS = clamp(pastControversySeverityIndex, 0, 100);
  const pTP = clamp(publicTransparencyPerception, 0, 100);
  const cCP = clamp(crisisCommunicationPreparedness, 0, 100);
  const sTI = clamp(stakeholderTrustIndex, 0, 100);
  const rCH = clamp(regulatoryComplianceHistory, 0, 100);

  // Weights for each factor (sum to 1.0)
  const weights = {
    sentiment: 0.20,
    mediaMentions: 0.15,
    ethics: 0.20,
    controversy: 0.15,
    transparency: 0.10,
    crisisComm: 0.10,
    trust: 0.05,
    compliance: 0.05
  };

  // Calculate risk contribution for each factor (higher value = higher risk)
  // For scores where higher is better, invert them (100 - score)

  // Social Media Sentiment: High sentiment = low risk. Invert.
  const sentimentRisk = (100 - sMSS) * weights.sentiment;

  // Negative Media Mentions: Higher count = higher risk. Normalize with a cap.
  // Assume 50 mentions is a 'max impact' equivalent for this factor on a 0-100 scale.
  const normalizedMediaMentions = Math.min(nMMM, 50) / 50 * 100; 
  const mediaMentionsRisk = normalizedMediaMentions * weights.mediaMentions;

  // Ethical Policy Adherence: High adherence = low risk. Invert.
  const ethicalRisk = (100 - ePAS) * weights.ethics;

  // Past Controversy Severity: Higher index = higher risk.
  const controversyRisk = pCS * weights.controversy;

  // Public Transparency Perception: High perception = low risk. Invert.
  const transparencyRisk = (100 - pTP) * weights.transparency;

  // Crisis Communication Preparedness: High preparedness = low risk. Invert.
  const crisisCommRisk = (100 - cCP) * weights.crisisComm;

  // Stakeholder Trust Index: High trust = low risk. Invert.
  const trustRisk = (100 - sTI) * weights.trust;

  // Regulatory Compliance History: High compliance = low risk. Invert.
  const complianceRisk = (100 - rCH) * weights.compliance;

  // Sum all weighted risks
  let totalRiskScore = 
    sentimentRisk + 
    mediaMentionsRisk + 
    ethicalRisk + 
    controversyRisk + 
    transparencyRisk + 
    crisisCommRisk + 
    trustRisk + 
    complianceRisk;

  // Ensure total score is within 0-100 range
  totalRiskScore = clamp(totalRiskScore, 0, 100);

  let riskCategory;
  if (totalRiskScore <= 25) {
    riskCategory = 'Low Risk';
  } else if (totalRiskScore <= 50) {
    riskCategory = 'Moderate Risk';
  } else if (totalRiskScore <= 75) {
    riskCategory = 'High Risk';
  } else {
    riskCategory = 'Critical Risk';
  }

  return {
    reputationalRiskScore: totalRiskScore,
    riskCategory: riskCategory
  };
}
